                        gapErrors.push(`Gap is too low, it is overlapping with bottom plate by ${removeTrailingZeroes(roundWithDecimals((Math.abs(comparedItem.bottomHeight) - (columnHeight / 2)) * 1000, 0.01), 2)} mm`);
