            }
            else {
                return ["/images/columns/centralColumn.svg", "/images/columns/rightColumn.svg"];
            }
        },
        gapTypesWithoutCustom() {
            const gapTypesWithoutCustom = [];
            gapTypes.forEach((elem) => {
                if (elem != "Custom") {
                    gapTypesWithoutCustom.push(elem);
                }
            })
            return gapTypesWithoutCustom;

        },
    }
